module sr_latch (
    input wire AntiIntuitive_S,
    input wire R,
    output reg Q,
    output reg Qb
);
    always @ (AntiIntuitive_S, R) begin
        if (AntiIntuitive_S && !R) begin
            Q = 1;
            Qb = 0;
        end else if (!AntiIntuitive_S && R) begin
            Q = 0;
            Qb = 1;
        end else if (!AntiIntuitive_S && !R) begin
            // Hold state
            Q = Q;
            Qb = Qb;
        end else begin
            // Invalid state (AntiIntuitive_S=1, R=1)
            Q = 1'bx; // or you can define a behavior for this case
            Qb = 1'bx;
        end
    end
endmodule
